#include <iostream>
#include <fstream>
#include <string>
#include <vector>

using namespace std;

struct ConfigData {
    string key;
    string value;
};

ConfigData* readConfigFile(const char* filename) {
    ifstream file(filename);
    vector<ConfigData> configData;

    // Read the configuration file line by line
    for (string line; getline(file, line); ) {
        // Ignore empty lines and comments
        if (line.empty() || line[0] == '#') continue;

        // Split the line into key and value
        auto pos = line.find('=');
        string key = line.substr(0, pos);
        string value = line.substr(pos + 1);

        // Add the configuration data to the vector
        configData.push_back({key, value});
    }

    // Return a pointer to the configuration data
    return &configData[0];
}